function bindTooltip(app: { getUiLocale(): string }, element: HTMLElement, helpTextEn: string, helpTextId: string) {
    let tooltipElement: HTMLDivElement | null = null;

    const showTooltip = () => {
        if (!getHelpModeActive()) return;
        if (tooltipElement) return;

        const uiLanguage = app.getUiLocale();
        const text = uiLanguage === "id" ? helpTextId : helpTextEn;
        if (!text) return;

        const tooltip = document.createElement("div");
        tooltip.classList.add("help-tooltip-container");
        tooltip.innerText = text;
        document.body.appendChild(tooltip);
        tooltipElement = tooltip;

        const rect = element.getBoundingClientRect();
        const tooltipRect = tooltip.getBoundingClientRect();
        
        let left = rect.left + (rect.width - tooltipRect.width) / 2;
        left = Math.max(10, Math.min(window.innerWidth - tooltipRect.width - 10, left));

        let top = rect.top - tooltipRect.height - 8 + window.scrollY;
        if (rect.top - tooltipRect.height - 8 < 10) {
            top = rect.bottom + 8 + window.scrollY;
        }

        tooltip.style.left = `${left}px`;
        tooltip.style.top = `${top}px`;

        requestAnimationFrame(() => {
            tooltip.classList.add("visible");
        });
    };

    const hideTooltip = () => {
        if (!tooltipElement) return;
        const el = tooltipElement;
        tooltipElement = null;
        el.classList.remove("visible");
        setTimeout(() => {
            el.remove();
        }, 150);
    };

    element.addEventListener("mouseenter", () => showTooltip());
    element.addEventListener("mouseleave", () => hideTooltip());
    element.addEventListener("click", (e) => {
        if (!getHelpModeActive()) return;
        e.stopPropagation();
        if (tooltipElement) {
            hideTooltip();
        } else {
            document.querySelectorAll(".help-tooltip-container").forEach(el => {
                el.classList.remove("visible");
                setTimeout(() => el.remove(), 150);
            });
            showTooltip();
        }
    });

    element.classList.add("has-help-text");
}

async function startApp() {
    const api = await getApi()

    const rootElement = document.getElementById("root");
    if (rootElement == null) {
        showErrorPopup("couldn't find root element", true)
        return;
    }

    // Get Host and App via Query
    const queryParams = new URLSearchParams(location.search)

    const hostIdStr = queryParams.get("hostId")
    const appIdStr = queryParams.get("appId")
    if (hostIdStr == null || appIdStr == null) {
        await showMessage("No Host or no App Id found")

        window.close()
        return
    }
    const hostId = Number.parseInt(hostIdStr)
    const appId = Number.parseInt(appIdStr)

    // event propagation on overlays
    const sidebarRoot = getSidebarRoot()
    if (sidebarRoot) {
        applyBrowserNativeBridgeModeClasses()
        stopPropagationOn(sidebarRoot)
        sidebarRoot.classList.add("stream-sidebar-root")
        sidebarRoot.querySelector(".sidebar-background")?.classList.add("stream-sidebar-background")
        sidebarRoot.querySelector("#sidebar-parent")?.classList.add("stream-sidebar-stage")
        const sidebarButton = sidebarRoot.querySelector("#sidebar-button") as HTMLButtonElement | null
        sidebarButton?.classList.add("stream-sidebar-trigger")
        if (sidebarButton) {
            sidebarButton.setAttribute("aria-label", "Open stream menu")
            sidebarButton.dataset.label = "MENU"
        }
        setSidebarStyle({
            edge: "right",
        })
        applyBrowserNativeBridgeModeClasses()
    }

    const modalBackground = getModalBackground()
    if (modalBackground) {
        stopPropagationOn(modalBackground)
    }

    // Start and Mount App
    const app = new ViewerApp(api, hostId, appId)
    app.mount(rootElement);

    (window as any)["app"] = app
}

// Prevent starting transition
window.requestAnimationFrame(() => {
    // Note: elements is a live array
    const elements = document.getElementsByClassName("prevent-start-transition")
    while (elements.length > 0) {
        elements.item(0)?.classList.remove("prevent-start-transition")
    }
})

startApp()

type ConnectionRouteState = "negotiating" | "direct" | "relay" | "websocket" | "failed"

type ConnectionRouteUpdate = {
    state: ConnectionRouteState
    detail: string
}

type DisplayTransitionPhase = "idle" | "intent_locked" | "reconnecting" | "verifying"
type DisplayTransitionTrigger = "orientation" | "fullscreen" | "bridge"
type NativeAndroidBridgeState = "hidden" | "button" | "open"
type VideoProgressSample = {
    kind: "frames" | "time"
    metric: number
}

function getShortConnectionRouteNote(state: ConnectionRouteState, detail?: string): string {
    const normalized = String(detail ?? "").trim()
    if (normalized) {
        if (/direct peer-to-peer/i.test(normalized)) {
            return "Shared route state"
        }
        if (/relay via turn|turn relay|relayed by the turn/i.test(normalized)) {
            return "TURN fallback active"
        }
        if (/websocket/i.test(normalized)) {
            return "Legacy relay active"
        }
        if (/failed|could not be created|noconnect/i.test(normalized)) {
            return "Direct path unavailable"
        }
        if (/trying|waiting|negotiat/i.test(normalized)) {
            return "Trying direct path"
        }
    }

    switch (state) {
    case "direct":
        return "Shared route state"
    case "relay":
        return "TURN fallback active"
    case "websocket":
        return "Legacy relay active"
    case "failed":
        return "Direct path unavailable"
    default:
        return "Trying direct path"
    }
}

