function normalizeQuickPadAutoApplyMode(raw: unknown): QuickPadAutoApplyMode {
    switch (raw) {
    case "favorite_first":
    case "app_only":
    case "favorite_only":
        return raw
    default:
        return "app_first"
    }
}

function normalizeMobilePerformanceProfile(raw: unknown): MobilePerformanceProfile {
    return raw == "low_memory" ? "low_memory" : "balanced"
}

function parseRequestedMobilePerformanceProfile(raw: string | null): MobilePerformanceProfile | null {
    const normalized = String(raw ?? "").trim().toLowerCase()
    if (!normalized) {
        return null
    }
    if (normalized === "low_memory" || normalized === "low-memory" || normalized === "lowmemory" || normalized === "lite") {
        return "low_memory"
    }
    if (normalized === "balanced" || normalized === "normal" || normalized === "default") {
        return "balanced"
    }
    return null
}

function normalizeStoredControllerConfig(raw?: Partial<StreamInputConfig["controllerConfig"]> | null): StreamInputConfig["controllerConfig"] {
    return {
        invertAB: !!raw?.invertAB,
        invertXY: !!raw?.invertXY,
        sendIntervalOverride: typeof raw?.sendIntervalOverride == "number" && Number.isFinite(raw.sendIntervalOverride)
            ? raw.sendIntervalOverride
            : null
    }
}

