function clampQuickPadTemplateCoord(value: number, min: number, max: number): number {
    return Math.max(min, Math.min(max, value))
}

function quickPadCoordToPercent(px: number, size: number): number {
    return Number(((px / Math.max(1, size)) * 100).toFixed(2))
}

function buildAdaptiveDs4QuickPadLayout(viewport: { width: number, height: number }): Partial<Record<QuickPadLayoutRole, { left: number, top: number }>> {
    const width = Math.max(280, Math.round(Number(viewport.width) || 0))
    const height = Math.max(180, Math.round(Number(viewport.height) || 0))
    const shortEdge = Math.min(width, height)
    const longEdge = Math.max(width, height)
    const isSmallPhone = shortEdge <= QUICK_PAD_SMALL_PHONE_SHORT_EDGE_MAX
        && longEdge <= QUICK_PAD_SMALL_PHONE_LONG_EDGE_MAX
    const compact = shortEdge <= QUICK_PAD_SMALL_PHONE_SHORT_EDGE_MAX
    const ultraCompact = shortEdge <= 360
    const portrait = height >= width

    let pad = 0
    let top = 0
    let buttonWidth = 0
    let touchpadWidth = 0
    let shoulderY = 0
    let triggerY = 0
    let clusterStep = 0
    let clusterTop = 0
    let leftBaseX = 0
    let rightBaseX = 0
    let analogDiameter = 0
    let leftAnalogX = 0
    let rightAnalogX = 0
    let analogY = 0

    if (isSmallPhone && portrait) {
        pad = 8
        top = 8
        buttonWidth = 62
        touchpadWidth = 84
        shoulderY = top + 38
        triggerY = shoulderY + 32
        clusterStep = clampQuickPadTemplateCoord(Math.round(shortEdge * 0.12), 40, 48)
        clusterTop = Math.max(140, height - ((clusterStep * 3) + 22))
        leftBaseX = pad
        rightBaseX = Math.max(pad, width - ((clusterStep * 3) + pad))
        analogDiameter = 74
        const analogGap = 16
        const analogMaxX = Math.max(pad, width - analogDiameter - pad)
        analogY = Math.max(clusterTop + clusterStep - 14, height - analogDiameter - 10)
        leftAnalogX = clampQuickPadTemplateCoord(Math.round(width * 0.14), pad, analogMaxX)
        rightAnalogX = clampQuickPadTemplateCoord(Math.round(width * 0.86) - analogDiameter, pad, analogMaxX)
        if (rightAnalogX - leftAnalogX < analogDiameter + analogGap) {
            leftAnalogX = pad
            rightAnalogX = analogMaxX
        }
    } else if (isSmallPhone) {
        pad = 8
        top = 6
        buttonWidth = 58
        touchpadWidth = 82
        shoulderY = top + 30
        triggerY = shoulderY + 28
        clusterStep = clampQuickPadTemplateCoord(Math.round(shortEdge * 0.11), 38, 44)
        clusterTop = Math.max(104, height - ((clusterStep * 3) + 12))
        leftBaseX = pad
        rightBaseX = Math.max(pad, width - ((clusterStep * 3) + pad))
        analogDiameter = 70
        const analogGap = 18
        const analogMaxX = Math.max(pad, width - analogDiameter - pad)
        analogY = Math.max(clusterTop + clusterStep - 18, height - analogDiameter - 8)
        leftAnalogX = clampQuickPadTemplateCoord(Math.round(width * 0.17), pad, analogMaxX)
        rightAnalogX = clampQuickPadTemplateCoord(Math.round(width * 0.83) - analogDiameter, pad, analogMaxX)
        if (rightAnalogX - leftAnalogX < analogDiameter + analogGap) {
            leftAnalogX = pad
            rightAnalogX = analogMaxX
        }
    } else {
        pad = ultraCompact ? 6 : compact ? 8 : 12
        top = compact ? 8 : 12
        buttonWidth = compact ? 66 : 78
        touchpadWidth = compact ? 82 : 96
        shoulderY = top + (compact ? 38 : 46)
        triggerY = shoulderY + (compact ? 34 : 40)
        clusterStep = compact
            ? clampQuickPadTemplateCoord(Math.round(shortEdge * 0.12), 44, 54)
            : 58
        const clusterBottomPad = compact ? 14 : 24
        const clusterTopMin = ultraCompact ? 80 : compact ? 92 : 112
        clusterTop = Math.max(clusterTopMin, height - ((clusterStep * 3) + clusterBottomPad))
        leftBaseX = pad
        rightBaseX = Math.max(pad, width - ((clusterStep * 3) + pad))
        analogDiameter = compact ? 78 : 90
        const analogGap = compact ? 10 : 14
        const analogMaxX = Math.max(pad, width - analogDiameter - pad)
        analogY = Math.max(clusterTopMin + (compact ? 52 : 60), height - (analogDiameter + (compact ? 14 : 20)))
        leftAnalogX = clampQuickPadTemplateCoord(Math.round(width * 0.18), pad, analogMaxX)
        rightAnalogX = clampQuickPadTemplateCoord(Math.round(width * 0.82) - analogDiameter, pad, analogMaxX)
        if (rightAnalogX - leftAnalogX < analogDiameter + analogGap) {
            leftAnalogX = pad
            rightAnalogX = analogMaxX
        }
    }

    const coreHalf = compact ? 28 : 26
    const shoulderHalfWidth = 33
    const shoulderHalfHeight = 18
    const triggerHalfWidth = 31
    const triggerHalfHeight = 17
    const touchHalfHeight = 17

    return {
        cluster_dpad: {
            left: quickPadCoordToPercent(leftBaseX + clusterStep + coreHalf, width),
            top: quickPadCoordToPercent(clusterTop + clusterStep + coreHalf, height)
        },
        cluster_face: {
            left: quickPadCoordToPercent(rightBaseX + clusterStep + coreHalf, width),
            top: quickPadCoordToPercent(clusterTop + clusterStep + coreHalf, height)
        },
        cluster_stick_left: {
            left: quickPadCoordToPercent(leftAnalogX + (analogDiameter / 2), width),
            top: quickPadCoordToPercent(analogY + (analogDiameter / 2), height)
        },
        cluster_stick_right: {
            left: quickPadCoordToPercent(rightAnalogX + (analogDiameter / 2), width),
            top: quickPadCoordToPercent(analogY + (analogDiameter / 2), height)
        },
        shoulder_lb: {
            left: quickPadCoordToPercent(pad + shoulderHalfWidth, width),
            top: quickPadCoordToPercent(shoulderY + shoulderHalfHeight, height)
        },
        trigger_lt: {
            left: quickPadCoordToPercent(pad + triggerHalfWidth, width),
            top: quickPadCoordToPercent(triggerY + triggerHalfHeight, height)
        },
        touch_top: {
            left: quickPadCoordToPercent(Math.max(pad, Math.round((width - touchpadWidth) / 2)) + (touchpadWidth / 2), width),
            top: quickPadCoordToPercent(top + touchHalfHeight, height)
        },
        trigger_rt: {
            left: quickPadCoordToPercent(Math.max(pad, width - buttonWidth - pad) + triggerHalfWidth, width),
            top: quickPadCoordToPercent(triggerY + triggerHalfHeight, height)
        },
        shoulder_rb: {
            left: quickPadCoordToPercent(Math.max(pad, width - buttonWidth - pad) + shoulderHalfWidth, width),
            top: quickPadCoordToPercent(shoulderY + shoulderHalfHeight, height)
        },
        face_y: {
            left: quickPadCoordToPercent(rightBaseX + clusterStep + coreHalf, width),
            top: quickPadCoordToPercent(clusterTop + coreHalf, height)
        },
        face_x: {
            left: quickPadCoordToPercent(rightBaseX + coreHalf, width),
            top: quickPadCoordToPercent(clusterTop + clusterStep + coreHalf, height)
        },
        face_b: {
            left: quickPadCoordToPercent(rightBaseX + (clusterStep * 2) + coreHalf, width),
            top: quickPadCoordToPercent(clusterTop + clusterStep + coreHalf, height)
        },
        face_a: {
            left: quickPadCoordToPercent(rightBaseX + clusterStep + coreHalf, width),
            top: quickPadCoordToPercent(clusterTop + (clusterStep * 2) + coreHalf, height)
        },
        dpad_up: {
            left: quickPadCoordToPercent(leftBaseX + clusterStep + coreHalf, width),
            top: quickPadCoordToPercent(clusterTop + coreHalf, height)
        },
        dpad_down: {
            left: quickPadCoordToPercent(leftBaseX + clusterStep + coreHalf, width),
            top: quickPadCoordToPercent(clusterTop + (clusterStep * 2) + coreHalf, height)
        },
        dpad_left: {
            left: quickPadCoordToPercent(leftBaseX + coreHalf, width),
            top: quickPadCoordToPercent(clusterTop + clusterStep + coreHalf, height)
        },
        dpad_right: {
            left: quickPadCoordToPercent(leftBaseX + (clusterStep * 2) + coreHalf, width),
            top: quickPadCoordToPercent(clusterTop + clusterStep + coreHalf, height)
        },
        stick_left: {
            left: quickPadCoordToPercent(leftAnalogX + (analogDiameter / 2), width),
            top: quickPadCoordToPercent(analogY + (analogDiameter / 2), height)
        },
        stick_right: {
            left: quickPadCoordToPercent(rightAnalogX + (analogDiameter / 2), width),
            top: quickPadCoordToPercent(analogY + (analogDiameter / 2), height)
        }
    }
}

function buildAdaptiveQuickPadTemplateLayout(
    template: QuickPadPromptTemplate,
    viewport: { width: number, height: number }
): Partial<Record<QuickPadLayoutRole, { left: number, top: number }>> {
    const ds4Static = QUICK_PAD_TEMPLATE_LAYOUTS.ds4
    const targetStatic = QUICK_PAD_TEMPLATE_LAYOUTS[template]
    const adaptiveDs4 = {
        ...ds4Static,
        ...buildAdaptiveDs4QuickPadLayout(viewport)
    }

    if (template === "ds4") {
        return adaptiveDs4
    }

    const adaptedTarget: Partial<Record<QuickPadLayoutRole, { left: number, top: number }>> = {
        ...targetStatic
    }

    for (const roleKey of Object.keys(adaptiveDs4) as QuickPadLayoutRole[]) {
        const basePoint = adaptiveDs4[roleKey]
        const sourceStatic = ds4Static[roleKey]
        const templateStatic = targetStatic[roleKey]
        if (!basePoint || !sourceStatic || !templateStatic) {
            continue
        }
        adaptedTarget[roleKey] = {
            left: clampQuickPadTemplateCoord(basePoint.left + (templateStatic.left - sourceStatic.left), 4, 96),
            top: clampQuickPadTemplateCoord(basePoint.top + (templateStatic.top - sourceStatic.top), 8, 92)
        }
    }

    return adaptedTarget
}

function getQuickPadPromptLabel(template: QuickPadPromptTemplate, role: QuickPadPromptRole): string {
    return QUICK_PAD_PROMPT_TEMPLATE_META[template]?.[role] ?? QUICK_PAD_PROMPT_TEMPLATE_META.ds4[role]
}

function sanitizeQuickPadCustomLabel(raw: unknown): string {
    return typeof raw == "string" ? raw.trim().slice(0, 10) : ""
}

function sanitizeQuickPadUserTemplateName(raw: unknown): string {
    return typeof raw == "string" ? raw.trim().replace(/\s+/g, " ").slice(0, 22) : ""
}

function sanitizeQuickPadCustomKey(raw: unknown): string {
    return typeof raw == "string"
        ? raw
            .trim()
            .toUpperCase()
            .replace(/\s*\+\s*/g, "+")
            .replace(/\s+/g, "")
            .slice(0, 24)
        : ""
}

function clampQuickPadCustomLeft(left: number): number {
    return Math.max(6, Math.min(94, left))
}

function clampQuickPadCustomTop(top: number): number {
    return Math.max(10, Math.min(90, top))
}

function clampQuickPadCustomScale(scale: number): number {
    return Math.max(0.72, Math.min(1.85, scale))
}

function clampQuickPadCustomOpacity(opacity: number): number {
    return Math.max(0.24, Math.min(1, opacity))
}

function applySoftQuickPadCustomSnap(value: number, targets: number[], threshold = QUICK_PAD_CUSTOM_SNAP_THRESHOLD): number {
    for (const target of targets) {
        if (Math.abs(value - target) <= threshold) {
            return target
        }
    }
    return value
}

function getQuickPadCustomBehaviorModeCopy(mode: QuickPadCustomBehaviorMode): { en: string, id: string } {
    switch (mode) {
    case "tap":
        return { en: "Tap", id: "Tap" }
    case "toggle":
        return { en: "Toggle", id: "Toggle" }
    case "turbo":
        return { en: "Turbo", id: "Turbo" }
    default:
        return { en: "Hold", id: "Tahan" }
    }
}

function getQuickPadCustomActionKindCopy(kind: "off" | "gamepad" | "keyboard" | "mouse"): { en: string, id: string } {
    switch (kind) {
    case "gamepad":
        return { en: "Gamepad", id: "Gamepad" }
    case "keyboard":
        return { en: "Keyboard", id: "Keyboard" }
    case "mouse":
        return { en: "Mouse", id: "Mouse" }
    default:
        return { en: "Disabled", id: "Nonaktif" }
    }
}

function getQuickPadCustomKindBadge(kind: "off" | "gamepad" | "keyboard" | "mouse"): string {
    switch (kind) {
    case "gamepad":
        return "PAD"
    case "keyboard":
        return "KEY"
    case "mouse":
        return "MSE"
    default:
        return "OFF"
    }
}

function getQuickPadCustomModeBadge(mode: QuickPadCustomBehaviorMode, isSequence = false): string {
    if (isSequence) {
        return "SEQ"
    }
    switch (mode) {
    case "tap":
        return "TAP"
    case "toggle":
        return "TOG"
    case "turbo":
        return "TBO"
    default:
        return "HLD"
    }
}

function normalizeQuickPadCustomBehaviorMode(raw: unknown): QuickPadCustomBehaviorMode {
    return raw == "tap" || raw == "toggle" || raw == "turbo"
        ? raw as QuickPadCustomBehaviorMode
        : "hold"
}

function getQuickPadCustomButtonBasePosition(index: number): { left: number, top: number } {
    return QUICK_PAD_CUSTOM_BUTTON_BASE_POSITIONS[index] ?? QUICK_PAD_CUSTOM_BUTTON_BASE_POSITIONS[0]
}

function normalizeQuickPadCustomButtonPrefs(raw: Partial<QuickPadCustomButtonPrefs> | null | undefined, index: number): QuickPadCustomButtonPrefs {
    const action = typeof raw?.action == "string" && raw.action in QUICK_PAD_CUSTOM_ACTION_META
        ? raw.action as QuickPadCustomActionId
        : "off"
    const basePosition = getQuickPadCustomButtonBasePosition(index)
    const left = typeof raw?.left == "number" && Number.isFinite(raw.left)
        ? clampQuickPadCustomLeft(raw.left)
        : basePosition.left
    const top = typeof raw?.top == "number" && Number.isFinite(raw.top)
        ? clampQuickPadCustomTop(raw.top)
        : basePosition.top
    const scale = typeof raw?.scale == "number" && Number.isFinite(raw.scale)
        ? clampQuickPadCustomScale(raw.scale)
        : 1
    const opacity = typeof raw?.opacity == "number" && Number.isFinite(raw.opacity)
        ? clampQuickPadCustomOpacity(raw.opacity)
        : 1
    return {
        action,
        mode: normalizeQuickPadCustomBehaviorMode(raw?.mode),
        label: sanitizeQuickPadCustomLabel(raw?.label),
        customKey: sanitizeQuickPadCustomKey(raw?.customKey),
        left,
        top,
        scale,
        opacity
    }
}

function resolveQuickPadCustomKeyToken(raw: string): { keyCode: number, label: string, shortLabel: string, isModifier: boolean } | null {
    const normalized = sanitizeQuickPadCustomKey(raw)
    if (!normalized) {
        return null
    }

    const aliasMap: Record<string, {
        key: keyof typeof StreamKeys
        label: string
        shortLabel?: string
        isModifier?: boolean
    }> = {
        ESC: { key: "VK_ESCAPE", label: "ESC" },
        ESCAPE: { key: "VK_ESCAPE", label: "ESC" },
        TAB: { key: "VK_TAB", label: "TAB" },
        ENTER: { key: "VK_RETURN", label: "ENTER" },
        RETURN: { key: "VK_RETURN", label: "ENTER" },
        SPACE: { key: "VK_SPACE", label: "SPACE" },
        SPACEBAR: { key: "VK_SPACE", label: "SPACE" },
        SHIFT: { key: "VK_SHIFT", label: "SHIFT", shortLabel: "S", isModifier: true },
        CTRL: { key: "VK_CONTROL", label: "CTRL", shortLabel: "C", isModifier: true },
        CONTROL: { key: "VK_CONTROL", label: "CTRL", shortLabel: "C", isModifier: true },
        ALT: { key: "VK_MENU", label: "ALT", shortLabel: "A", isModifier: true },
        MENU: { key: "VK_MENU", label: "ALT", shortLabel: "A", isModifier: true },
        OPTION: { key: "VK_MENU", label: "ALT", shortLabel: "A", isModifier: true },
        WIN: { key: "VK_LWIN", label: "WIN", shortLabel: "WIN", isModifier: true },
        WINDOWS: { key: "VK_LWIN", label: "WIN", shortLabel: "WIN", isModifier: true },
        CMD: { key: "VK_LWIN", label: "WIN", shortLabel: "WIN", isModifier: true },
        COMMAND: { key: "VK_LWIN", label: "WIN", shortLabel: "WIN", isModifier: true },
        SUPER: { key: "VK_LWIN", label: "WIN", shortLabel: "WIN", isModifier: true },
        BACKSPACE: { key: "VK_BACK", label: "BACKSPACE", shortLabel: "BSP" },
        DEL: { key: "VK_DELETE", label: "DEL" },
        DELETE: { key: "VK_DELETE", label: "DEL" },
        INS: { key: "VK_INSERT", label: "INS" },
        INSERT: { key: "VK_INSERT", label: "INS" },
        HOME: { key: "VK_HOME", label: "HOME" },
        END: { key: "VK_END", label: "END" },
        PGUP: { key: "VK_PRIOR", label: "PGUP" },
        PAGEUP: { key: "VK_PRIOR", label: "PGUP" },
        PGDN: { key: "VK_NEXT", label: "PGDN" },
        PAGEDOWN: { key: "VK_NEXT", label: "PGDN" },
        UP: { key: "VK_UP", label: "UP" },
        DOWN: { key: "VK_DOWN", label: "DOWN" },
        LEFT: { key: "VK_LEFT", label: "LEFT" },
        RIGHT: { key: "VK_RIGHT", label: "RIGHT" }
    }

    const alias = aliasMap[normalized]
    if (alias) {
        return {
            keyCode: StreamKeys[alias.key],
            label: alias.label,
            shortLabel: alias.shortLabel ?? alias.label,
            isModifier: alias.isModifier === true
        }
    }

    if (/^[A-Z]$/.test(normalized)) {
        const keyName = `VK_KEY_${normalized}` as keyof typeof StreamKeys
        const keyCode = StreamKeys[keyName]
        if (typeof keyCode == "number") {
            return { keyCode, label: normalized, shortLabel: normalized, isModifier: false }
        }
    }

    if (/^[0-9]$/.test(normalized)) {
        const keyName = `VK_KEY_${normalized}` as keyof typeof StreamKeys
        const keyCode = StreamKeys[keyName]
        if (typeof keyCode == "number") {
            return { keyCode, label: normalized, shortLabel: normalized, isModifier: false }
        }
    }

    const functionMatch = normalized.match(/^F([1-9]|1[0-2])$/)
    if (functionMatch) {
        const keyName = `VK_F${functionMatch[1]}` as keyof typeof StreamKeys
        const keyCode = StreamKeys[keyName]
        if (typeof keyCode == "number") {
            return { keyCode, label: normalized, shortLabel: normalized, isModifier: false }
        }
    }

    return null
}

function resolveQuickPadCustomKeyBinding(raw: string): QuickPadResolvedCustomKeyBinding | null {
    const normalized = sanitizeQuickPadCustomKey(raw)
    if (!normalized) {
        return null
    }

    const tokens = normalized.split("+").map((token) => token.trim()).filter(Boolean)
    if (!tokens.length) {
        return null
    }

    const resolvedTokens = tokens.map((token) => resolveQuickPadCustomKeyToken(token))
    if (resolvedTokens.some((token) => token == null)) {
        return null
    }

    const typedTokens = resolvedTokens as Array<NonNullable<typeof resolvedTokens[number]>>
    if (typedTokens.length === 1) {
        const token = typedTokens[0]
        return {
            keyCode: token.keyCode,
            modifierKeyCodes: [],
            label: token.label,
            shortLabel: token.shortLabel
        }
    }

    const modifierTokens = typedTokens.slice(0, -1)
    if (modifierTokens.some((token) => !token.isModifier)) {
        return null
    }

    const mainToken = typedTokens[typedTokens.length - 1]
    const modifierKeyCodes = Array.from(new Set(modifierTokens.map((token) => token.keyCode)))
    return {
        keyCode: mainToken.keyCode,
        modifierKeyCodes,
        label: typedTokens.map((token) => token.label).join("+"),
        shortLabel: [
            ...modifierTokens.map((token) => token.shortLabel),
            mainToken.label
        ].join("+")
    }
}

function resolveQuickPadCustomKeySequence(raw: string): QuickPadResolvedCustomKeySequence | null {
    const normalized = sanitizeQuickPadCustomKey(raw)
    if (!normalized) {
        return null
    }

    const parts = normalized.split(/[>,;]+/).map((part) => part.trim()).filter(Boolean)
    if (!parts.length) {
        return null
    }

    const bindings = parts.map((part) => resolveQuickPadCustomKeyBinding(part))
    if (bindings.some((binding) => binding == null)) {
        return null
    }

    const typedBindings = bindings as Array<NonNullable<typeof bindings[number]>>
    return {
        bindings: typedBindings,
        label: typedBindings.map((binding) => binding.label).join(", "),
        shortLabel: typedBindings.map((binding) => binding.shortLabel).join(" / ")
    }
}

function appendQuickPadCustomBuilderToken(currentRaw: string, tokenRaw: string): string {
    const current = sanitizeQuickPadCustomKey(currentRaw)
    const token = sanitizeQuickPadCustomKey(tokenRaw)
    const tokenMeta = resolveQuickPadCustomKeyToken(token)
    if (!tokenMeta) {
        return current
    }
    if (!current) {
        return token
    }
    if (current.endsWith(",") || current.endsWith("+")) {
        return `${current}${token}`
    }

    const lastStep = current.split(",").pop() ?? ""
    const hasMainKey = lastStep
        .split("+")
        .filter(Boolean)
        .map((part) => resolveQuickPadCustomKeyToken(part))
        .some((part) => part != null && !part.isModifier)

    return `${current}${hasMainKey ? "," : "+"}${token}`
}

function cloneQuickPadCustomButtons(buttons?: Array<QuickPadCustomButtonPrefs> | null): QuickPadCustomButtonPrefs[] {
    const nextButtons = Array.isArray(buttons) ? buttons : []
    return Array.from({ length: QUICK_PAD_CUSTOM_BUTTON_SLOT_COUNT }, (_, index) =>
        normalizeQuickPadCustomButtonPrefs(nextButtons[index], index)
    )
}

function hasActiveQuickPadCustomButtons(prefs: QuickPadOverlayPrefs): boolean {
    return prefs.customButtons.some((button) => button.action !== "off")
}

