type FullscreenCapableElement = HTMLElement & {
    requestFullscreen?: ((options?: FullscreenOptions) => Promise<void> | void) | undefined
    webkitRequestFullscreen?: (() => Promise<void> | void) | undefined
    webkitRequestFullScreen?: (() => Promise<void> | void) | undefined
    webkitEnterFullscreen?: (() => Promise<void> | void) | undefined
}

type FullscreenCapableDocument = Document & {
    webkitFullscreenElement?: Element | null
    webkitExitFullscreen?: (() => Promise<void> | void) | undefined
    webkitCancelFullScreen?: (() => Promise<void> | void) | undefined
    webkitIsFullScreen?: boolean
}

