function getStreamQualityFpsPresetIdForValue(fps: number): StreamQualityFpsPresetId {
    const rounded = Math.max(1, Math.round(fps || 0))
    return (STREAM_QUALITY_FPS_PRESET_VALUES as readonly number[]).indexOf(rounded) >= 0
        ? String(rounded) as StreamQualityFpsPresetId
        : "custom"
}

