function getBitrateForStreamQualityClarityPreset(presetId: StreamClarityPresetId): number {
    return STREAM_CLARITY_PRESETS[presetId].bitrate
}

function getStreamQualityClarityPresetIdForBitrate(bitrate: number): StreamClarityPresetId {
    const order: StreamClarityPresetId[] = ["540p", "720p", "1080p", "2k", "4k"]
    let bestPreset = order[0]
    let bestDistance = Number.POSITIVE_INFINITY

    for (const presetId of order) {
        const distance = Math.abs(bitrate - STREAM_CLARITY_PRESETS[presetId].bitrate)
        if (distance < bestDistance) {
            bestDistance = distance
            bestPreset = presetId
        }
    }

    return bestPreset
}

function getStreamQualityResolutionPresetDefinition(
    presetId: Exclude<StreamQualityResolutionPresetId, "custom">,
    viewportSize: [number, number] = getStreamQualityViewportSize()
): {
    label: string
    width: number
    height: number
    videoSize: Settings["videoSize"]
} {
    if (presetId == "device") {
        const [width, height] = getDeviceMatchStreamerSize(viewportSize)
        return {
            label: "Device",
            width,
            height,
            videoSize: "native"
        }
    }

    const preset = STREAM_QUALITY_RESOLUTION_PRESETS[presetId]
    const responsiveSize = getResponsiveStreamTierSize(preset.videoSize, viewportSize)
    if (!responsiveSize) {
        return preset
    }

    return {
        ...preset,
        width: responsiveSize[0],
        height: responsiveSize[1]
    }
}

function getStreamQualityViewportSize(): [number, number] {
    return [
        Math.max(document.documentElement.clientWidth || 0, window.innerWidth || 0),
        Math.max(document.documentElement.clientHeight || 0, window.innerHeight || 0)
    ]
}

function getStreamQualityResolutionSizeFromSettings(
    settings: Settings,
    viewportSize: [number, number] = getStreamQualityViewportSize()
): { width: number, height: number } {
    const [width, height] = getStreamerSize(settings, viewportSize)
    return { width, height }
}

function getStreamQualityResolutionPresetIdForSettings(settings: Settings): StreamQualityResolutionPresetId {
    if (settings.videoSize == "720p") {
        return "720p"
    }
    if (settings.videoSize == "1080p") {
        return "1080p"
    }
    if (settings.videoSize == "1440p") {
        return "2k"
    }
    if (settings.videoSize == "4k") {
        return "4k"
    }
    if (settings.videoSize == "native") {
        return "device"
    }
    if (settings.videoSize == "custom" && settings.videoSizeCustom.width == 640 && settings.videoSizeCustom.height == 360) {
        return "360p"
    }

    return "custom"
}

function getStreamQualityResolutionLabelForSettings(
    settings: Settings,
    viewportSize: [number, number] = getStreamQualityViewportSize()
): string {
    const presetId = getStreamQualityResolutionPresetIdForSettings(settings)
    if (presetId != "custom") {
        if (presetId == "device") {
            const size = getStreamQualityResolutionSizeFromSettings(settings, viewportSize)
            return `Device ${size.width}x${size.height}`
        }
        return STREAM_QUALITY_RESOLUTION_PRESETS[presetId].label
    }
    if (settings.videoSize == "4k") {
        return "4K"
    }

    const size = getStreamQualityResolutionSizeFromSettings(settings, viewportSize)
    return size.width > 0 && size.height > 0
        ? `${size.width}x${size.height}`
        : "Custom"
}

function getStreamQualityResolutionSettingsForPreset(
    presetId: Exclude<StreamQualityResolutionPresetId, "custom">
): Pick<Settings, "videoSize" | "videoSizeCustom"> {
    const preset = getStreamQualityResolutionPresetDefinition(presetId)
    return {
        videoSize: preset.videoSize,
        videoSizeCustom: {
            width: preset.width,
            height: preset.height
        }
    }
}

