const STREAM_DESKTOP_RELATIVE_MOUSE_OPT_IN_STORAGE_KEY = "ML_DESKTOP_RELATIVE_MOUSE_OPT_IN"

function normalizeStoredStreamInputConfig(raw?: Partial<StreamInputConfig> | null): StreamInputConfig {
    const defaults = defaultStreamInputConfig()
    const mouseMode = raw?.mouseMode == "relative" || raw?.mouseMode == "follow" || raw?.mouseMode == "pointAndDrag"
        ? raw.mouseMode
        : defaults.mouseMode
    const mouseScrollMode = raw?.mouseScrollMode == "normal" ? "normal" : defaults.mouseScrollMode
    const touchMode = raw?.touchMode == "touch" || raw?.touchMode == "mouseRelative" || raw?.touchMode == "pointAndDrag"
        ? raw.touchMode
        : defaults.touchMode
    const touchSensitivity = typeof raw?.touchSensitivity == "number" && Number.isFinite(raw.touchSensitivity)
        ? Math.max(STREAM_TOUCH_SENSITIVITY_MIN, Math.min(STREAM_TOUCH_SENSITIVITY_MAX, raw.touchSensitivity))
        : defaults.touchSensitivity
    const touchLongPressMs = typeof raw?.touchLongPressMs == "number" && Number.isFinite(raw.touchLongPressMs)
        ? Math.max(STREAM_TOUCH_LONG_PRESS_MIN_MS, Math.min(STREAM_TOUCH_LONG_PRESS_MAX_MS, Math.round(raw.touchLongPressMs)))
        : defaults.touchLongPressMs
    const twoFingerRightClick = typeof raw?.twoFingerRightClick == "boolean"
        ? raw.twoFingerRightClick
        : defaults.twoFingerRightClick

    return {
        mouseMode,
        mouseScrollMode,
        touchMode,
        touchSensitivity,
        touchLongPressMs,
        twoFingerRightClick,
        controllerConfig: normalizeStoredControllerConfig(raw?.controllerConfig)
    }
}

function shouldMigrateLegacyDesktopMouseMode(config: StreamInputConfig): boolean {
    return config.mouseMode === "relative"
        && config.mouseScrollMode === "highres"
        && config.touchMode === "mouseRelative"
        && Math.abs(config.touchSensitivity - 0.9) < 0.0001
        && config.touchLongPressMs === 300
        && config.twoFingerRightClick === true
        && config.controllerConfig.invertAB === false
        && config.controllerConfig.invertXY === false
        && config.controllerConfig.sendIntervalOverride == null
}

function isDesktopRelativeMouseOptedIn(): boolean {
    try {
        return window.localStorage.getItem(STREAM_DESKTOP_RELATIVE_MOUSE_OPT_IN_STORAGE_KEY) == "1"
    } catch {
        return false
    }
}

function persistDesktopRelativeMouseOptIn(enabled: boolean) {
    try {
        if (enabled) {
            window.localStorage.setItem(STREAM_DESKTOP_RELATIVE_MOUSE_OPT_IN_STORAGE_KEY, "1")
        } else {
            window.localStorage.removeItem(STREAM_DESKTOP_RELATIVE_MOUSE_OPT_IN_STORAGE_KEY)
        }
    } catch {
        // ignore storage failures
    }
}

function shouldMigrateLegacyMobileTouchMode(config: StreamInputConfig): boolean {
    return (
        config.touchMode === "pointAndDrag"
        || config.mouseMode === "pointAndDrag"
        || (config.touchMode === "mouseRelative" && config.mouseMode !== "relative")
    )
        && config.mouseScrollMode === "highres"
        && config.twoFingerRightClick === true
        && config.controllerConfig.invertAB === false
        && config.controllerConfig.invertXY === false
        && config.controllerConfig.sendIntervalOverride == null
}

function loadStoredStreamInputConfig(): StreamInputConfig {
    try {
        const raw = window.localStorage.getItem(STREAM_INPUT_CONFIG_STORAGE_KEY)
        if (raw) {
            return normalizeStoredStreamInputConfig(JSON.parse(raw))
        }
    } catch {
        // fall through
    }

    return normalizeStoredStreamInputConfig()
}

function persistStoredStreamInputConfig(config: StreamInputConfig) {
    try {
        window.localStorage.setItem(STREAM_INPUT_CONFIG_STORAGE_KEY, JSON.stringify(normalizeStoredStreamInputConfig(config)))
    } catch {
        // ignore storage failures
    }
}

function hasStoredStreamInputConfig(): boolean {
    try {
        return window.localStorage.getItem(STREAM_INPUT_CONFIG_STORAGE_KEY) != null
    } catch {
        return false
    }
}

function getStoredStreamInputAppPresetKey(scopeId: string) {
    return `${STREAM_INPUT_APP_PRESET_STORAGE_KEY}:${scopeId}`
}

function loadStoredStreamInputAppPreset(scopeId: string): StreamInputConfig["controllerConfig"] | null {
    try {
        const raw = window.localStorage.getItem(getStoredStreamInputAppPresetKey(scopeId))
        if (!raw) {
            return null
        }
        return normalizeStoredControllerConfig(JSON.parse(raw))
    } catch {
        return null
    }
}

function hasStoredStreamInputAppPreset(scopeId: string): boolean {
    return loadStoredStreamInputAppPreset(scopeId) != null
}

function persistStoredStreamInputAppPreset(scopeId: string, config: StreamInputConfig["controllerConfig"]): boolean {
    try {
        window.localStorage.setItem(getStoredStreamInputAppPresetKey(scopeId), JSON.stringify(normalizeStoredControllerConfig(config)))
        return true
    } catch {
        return false
    }
}

function clearStoredStreamInputAppPreset(scopeId: string): boolean {
    try {
        window.localStorage.removeItem(getStoredStreamInputAppPresetKey(scopeId))
        return true
    } catch {
        return false
    }
}

function normalizeStoredTouchAppPreset(raw?: Partial<StreamTouchAppPreset> | null): StreamTouchAppPreset {
    const normalized = normalizeStoredStreamInputConfig(raw as Partial<StreamInputConfig> | null | undefined)
    return {
        mouseMode: normalized.mouseMode,
        touchMode: normalized.touchMode,
        touchSensitivity: normalized.touchSensitivity,
        touchLongPressMs: normalized.touchLongPressMs,
        twoFingerRightClick: normalized.twoFingerRightClick
    }
}

function getStoredStreamTouchAppPresetKey(scopeId: string) {
    return `${STREAM_TOUCH_APP_PRESET_STORAGE_KEY}:${scopeId}`
}

function loadStoredStreamTouchAppPreset(scopeId: string): StreamTouchAppPreset | null {
    try {
        const raw = window.localStorage.getItem(getStoredStreamTouchAppPresetKey(scopeId))
        if (!raw) {
            return null
        }
        return normalizeStoredTouchAppPreset(JSON.parse(raw))
    } catch {
        return null
    }
}

function hasStoredStreamTouchAppPreset(scopeId: string): boolean {
    return loadStoredStreamTouchAppPreset(scopeId) != null
}

function persistStoredStreamTouchAppPreset(scopeId: string, config: StreamInputConfig): boolean {
    try {
        window.localStorage.setItem(
            getStoredStreamTouchAppPresetKey(scopeId),
            JSON.stringify(normalizeStoredTouchAppPreset(config))
        )
        return true
    } catch {
        return false
    }
}

function clearStoredStreamTouchAppPreset(scopeId: string): boolean {
    try {
        window.localStorage.removeItem(getStoredStreamTouchAppPresetKey(scopeId))
        return true
    } catch {
        return false
    }
}

function applyStoredTouchAppPreset(baseConfig: StreamInputConfig, preset: StreamTouchAppPreset): StreamInputConfig {
    const normalizedPreset = normalizeStoredTouchAppPreset(preset)
    return {
        ...baseConfig,
        mouseMode: normalizedPreset.mouseMode,
        touchMode: normalizedPreset.touchMode,
        touchSensitivity: normalizedPreset.touchSensitivity,
        touchLongPressMs: normalizedPreset.touchLongPressMs,
        twoFingerRightClick: normalizedPreset.twoFingerRightClick
    }
}

function areStoredControllerConfigsEqual(
    left: StreamInputConfig["controllerConfig"] | null | undefined,
    right: StreamInputConfig["controllerConfig"] | null | undefined
) {
    const normalizedLeft = normalizeStoredControllerConfig(left)
    const normalizedRight = normalizeStoredControllerConfig(right)
    return normalizedLeft.invertAB === normalizedRight.invertAB
        && normalizedLeft.invertXY === normalizedRight.invertXY
        && normalizedLeft.sendIntervalOverride === normalizedRight.sendIntervalOverride
}

