function getConnectionRouteUpdate(line: string): ConnectionRouteUpdate | null {
    if (line.startsWith("Trying WebRTC transport") || line.startsWith("Using transport: webrtc")) {
        return {
            state: "negotiating",
            detail: "Trying to establish a direct WebRTC path."
        }
    }
    if (line.startsWith("Trying direct WebRTC path") || line.startsWith("Retrying direct WebRTC path")) {
        return {
            state: "negotiating",
            detail: line
        }
    }
    if (line.startsWith("Retrying WebRTC with TURN relay fallback")) {
        return {
            state: "negotiating",
            detail: line
        }
    }
    if (line.startsWith("Trying Web Socket transport") || line.startsWith("Using transport: websocket")) {
        return {
            state: "websocket",
            detail: "Streaming is using the legacy WebSocket relay path."
        }
    }
    if (line.startsWith("WebRTC route: direct peer-to-peer")) {
        return {
            state: "direct",
            detail: line
        }
    }
    if (line.startsWith("WebRTC route: relay via TURN")) {
        return {
            state: "relay",
            detail: line
        }
    }
    if (line.includes("Failed to establish a direct WebRTC connection") || line.includes("Failed to establish a WebRTC connection.")) {
        return {
            state: "failed",
            detail: line
        }
    }
    if (line.includes("The active WebRTC connection was lost.")) {
        return {
            state: "failed",
            detail: "The active WebRTC path was lost."
        }
    }
    if (line.includes("The active WebSocket relay connection was lost.")) {
        return {
            state: "failed",
            detail: "The WebSocket relay path was lost."
        }
    }

    return null
}

