    private readonly onStreamChromeViewportChangeBound = () => {
        this.applyDeviceUiProfileClasses()
        this.syncStreamChromeBounds(true)
        this.syncMobileOrientationPromptState()
        this.syncMobileNativeCursorViewport()
        this.scheduleBridgeOrientationEnforcement(120)
        if (this.isFullscreen()) {
            this.scheduleFastFullscreenDeviceMatchSync()
        }
        this.scheduleDynamicDeviceMatchReconnect("resize")
    }
