    private getDesktopLayoutTemplateSummary(meta: QuickPadUserTemplateMeta = this.getDesktopLayoutSelectedTemplateMeta()) {
        const orientation = this.getQuickPadCurrentOrientation()
        const buttonCount = orientation === "portrait" ? meta.portraitButtonCount : meta.landscapeButtonCount
        const slotLabel = this.getDesktopLayoutTemplateSlotLabel()
        if (!meta.exists) {
            return `${slotLabel} empty on this browser`
        }
        const flags = [
            this.getDesktopLayoutTemplateTypeLabel(meta.layoutType),
            `${buttonCount} btn${buttonCount === 1 ? "" : "s"}`
        ]
        if (meta.favorite) {
            flags.push("Fav")
        }
        if (meta.locked) {
            flags.push("Locked")
        }
        return `${meta.name} / ${flags.join(" / ")}`
    }

    private getDesktopLayoutTemplateNote(meta: QuickPadUserTemplateMeta = this.getDesktopLayoutSelectedTemplateMeta()) {
        const baseNote = "Full drag and author tuning still stays in QuickPad Tuning."
        const slotLabel = this.getDesktopLayoutTemplateSlotLabel()
        if (!meta.exists) {
            return `${slotLabel} is empty. Save captures the live QuickPad layout into that reusable browser slot. ${baseNote}`
        }
        const flags: string[] = []
        if (meta.favorite) {
            flags.push("Pinned as favorite")
        }
        if (meta.locked) {
            flags.push("Locked against overwrite")
        }
        if (meta.orientationWarning === "portrait_missing") {
            flags.push("Portrait layout is sparse")
        } else if (meta.orientationWarning === "landscape_missing") {
            flags.push("Landscape layout is sparse")
        }
        const detailNote = flags.length > 0 ? ` ${flags.join(". ")}.` : ""
        return `${slotLabel} is ready for fast desktop recall. ${meta.preview}.${detailNote} ${baseNote}`
    }

    private getDesktopQuickPadInputProfileIdForPrefs(prefs: QuickPadOverlayPrefs): QuickPadInputProfileId {
        const nearlyEqual = (a: number, b: number) => Math.abs(a - b) < 0.011

        for (const profileId of Object.keys(QUICK_PAD_INPUT_PROFILES) as Array<Exclude<QuickPadInputProfileId, "custom">>) {
            const profile = QUICK_PAD_INPUT_PROFILES[profileId]
            if (
                (profile.stickSensitivity == null || nearlyEqual(prefs.stickSensitivity, profile.stickSensitivity))
                && (profile.triggerSensitivity == null || nearlyEqual(prefs.triggerSensitivity, profile.triggerSensitivity))
                && (profile.triggerCurve == null || prefs.triggerCurve === profile.triggerCurve)
                && (profile.touchButtonMode == null || prefs.touchButtonMode === profile.touchButtonMode)
                && (profile.touchpadSensitivity == null || nearlyEqual(prefs.touchpadSensitivity, profile.touchpadSensitivity))
                && (profile.touchpadTapMode == null || prefs.touchpadTapMode === profile.touchpadTapMode)
                && (profile.haptics == null || prefs.haptics === profile.haptics)
                && (profile.turboEnabled == null || prefs.turboEnabled === profile.turboEnabled)
                && (profile.turboRateMs == null || Math.abs(prefs.turboRateMs - profile.turboRateMs) <= 1)
                && (profile.conflictGuardEnabled == null || prefs.conflictGuardEnabled === profile.conflictGuardEnabled)
                && (profile.latencyHud == null || prefs.latencyHud === profile.latencyHud)
            ) {
                return profileId
            }
        }

        return "custom"
    }

    private getDesktopQuickPadPresetIdForPrefs(prefs: QuickPadOverlayPrefs): QuickPadPresetId {
        const nearlyEqual = (a: number, b: number) => Math.abs(a - b) < 0.011

        if (hasActiveQuickPadCustomButtons(prefs)) {
            return "custom"
        }

        for (const presetId of Object.keys(QUICK_PAD_PRESETS) as Array<Exclude<QuickPadPresetId, "custom">>) {
            const preset = QUICK_PAD_PRESETS[presetId]
            if (
                prefs.profile === preset.profile
                && nearlyEqual(prefs.leftDeadzone, preset.leftDeadzone)
                && nearlyEqual(prefs.rightDeadzone, preset.rightDeadzone)
                && nearlyEqual(prefs.scale, preset.scale)
                && nearlyEqual(prefs.opacity, preset.opacity)
                && nearlyEqual(prefs.stickSensitivity, preset.stickSensitivity)
                && nearlyEqual(prefs.triggerSensitivity, preset.triggerSensitivity)
                && prefs.triggerCurve === preset.triggerCurve
                && prefs.touchButtonMode === preset.touchButtonMode
                && nearlyEqual(prefs.touchpadSensitivity, preset.touchpadSensitivity)
                && prefs.touchpadTapMode === preset.touchpadTapMode
                && prefs.haptics === preset.haptics
                && prefs.idleFade === preset.idleFade
                && prefs.turboEnabled === preset.turboEnabled
                && Math.abs(prefs.turboRateMs - preset.turboRateMs) <= 1
                && prefs.conflictGuardEnabled === preset.conflictGuardEnabled
                && prefs.latencyHud === preset.latencyHud
                && !hasActiveQuickPadCustomButtons(preset)
            ) {
                return presetId
            }
        }

        return "custom"
    }

    private getDesktopPadScenePresetId(): GamepadScenePresetId | "custom" {
        const orientation = this.getQuickPadCurrentOrientation()
        const prefs = this.getQuickPadPrefs(orientation)
        const config = this.getInputConfig()
        const quickPadPresetId = this.getDesktopQuickPadPresetIdForPrefs(prefs)
        const inputProfileId = this.getDesktopQuickPadInputProfileIdForPrefs(prefs)
        const touchPresetId = this.getTouchPresetIdForConfig(config)

        for (const presetId of Object.keys(GAMEPAD_SCENE_PRESETS) as GamepadScenePresetId[]) {
            const preset = GAMEPAD_SCENE_PRESETS[presetId]
            if (
                quickPadPresetId === preset.quickPadPreset
                && inputProfileId === preset.inputProfile
                && touchPresetId === preset.touchPreset
            ) {
                return presetId
            }
        }

        return "custom"
    }

