    private getDesktopPadGuardLabel() {
        const orientation = this.getQuickPadCurrentOrientation()
        const prefs = this.getQuickPadPrefs(orientation)
        return prefs.conflictGuardEnabled ? "Guard On" : "Guard Off"
    }

    private getDesktopPadNote() {
        const input = this.getStream()?.getInput()
        const padEnabled = input?.isVirtualControllerEnabled() ?? false
        const connected = input?.isVirtualControllerConnected() ?? false
        if (!padEnabled) {
            return "Pad deck can arm QuickPad, switch play style, and reopen deeper tuning without forcing the full sidebar."
        }
        if (this.connectedPhysicalGamepadIds.size > 0 && this.isQuickPadConflictGuardActive()) {
            return "Physical pad detected, so QuickPad taps pause while Conflict Guard stays on. Turn Guard Off if you want both inputs together."
        }
        if (!connected) {
            return "QuickPad is armed, but the virtual controller slot is not confirmed yet. Use Reconnect if the host dropped the controller."
        }
        return "Panel pad is live. Scene buttons keep QuickPad, touch, and fallback desktop behavior aligned in one place."
    }

