    private hasControllerAppPreset() {
        return hasStoredStreamInputAppPreset(this.getControllerAppPresetScopeId())
    }

    private readControllerAppPreset() {
        return loadStoredStreamInputAppPreset(this.getControllerAppPresetScopeId())
    }

    private saveControllerAppPreset() {
        return persistStoredStreamInputAppPreset(this.getControllerAppPresetScopeId(), this.getInputConfig().controllerConfig)
    }

    private loadControllerAppPreset() {
        const preset = this.readControllerAppPreset()
        if (!preset) {
            return false
        }
        this.setInputConfig({
            ...this.getInputConfig(),
            controllerConfig: preset
        })
        return true
    }

    private clearControllerAppPreset() {
        return clearStoredStreamInputAppPreset(this.getControllerAppPresetScopeId())
    }

    private applySavedControllerAppPresetIfPresent() {
        const preset = this.readControllerAppPreset()
        if (!preset) {
            return
        }
        this.inputConfig = {
            ...this.inputConfig,
            controllerConfig: preset
        }
        persistStoredStreamInputConfig(this.inputConfig)
    }

    private readDesktopPadTouchAppPreset() {
        return loadStoredStreamTouchAppPreset(this.getQuickPadPresetScopeId())
    }

    private saveDesktopPadAppPreset() {
        const quickPadSaved = this.saveQuickPadAppPreset()
        const touchSaved = persistStoredStreamTouchAppPreset(this.getQuickPadPresetScopeId(), this.getInputConfig())
        return quickPadSaved && touchSaved
    }

    private loadDesktopPadAppPreset() {
        const quickPadLoaded = this.loadQuickPadAppPreset()
        const touchPreset = this.readDesktopPadTouchAppPreset()
        if (touchPreset) {
            this.setInputConfig(applyStoredTouchAppPreset(this.getInputConfig(), touchPreset))
        }
        return quickPadLoaded || touchPreset != null
    }

    private clearDesktopPadAppPreset() {
        const quickPadCleared = this.clearQuickPadAppPreset()
        const touchCleared = clearStoredStreamTouchAppPreset(this.getQuickPadPresetScopeId())
        return quickPadCleared || touchCleared
    }

    private applySavedDesktopPadAppPresetIfPresent() {
        const touchPreset = this.readDesktopPadTouchAppPreset()
        if (!touchPreset) {
            return
        }
        this.inputConfig = applyStoredTouchAppPreset(this.inputConfig, touchPreset)
        persistStoredStreamInputConfig(this.inputConfig)
    }

    private getDesktopPadMemoryLabel() {
        const hasQuickPadPreset = this.hasQuickPadAppPreset()
        const hasTouchPreset = hasStoredStreamTouchAppPreset(this.getQuickPadPresetScopeId())
        if (hasQuickPadPreset && hasTouchPreset) {
            return "Saved"
        }
        if (hasQuickPadPreset) {
            return "QuickPad only"
        }
        if (hasTouchPreset) {
            return "Touch only"
        }
        return "Empty"
    }

    private getDesktopBindingsMemoryLabel() {
        const preset = this.readControllerAppPreset()
        if (!preset) {
            return "No app save"
        }
        if (areStoredControllerConfigsEqual(preset, this.getInputConfig().controllerConfig)) {
            return "Saved / Live"
        }
        return "Saved / Staged"
    }

    private openDesktopSidebarSection(section: SidebarPanelSectionId, selector?: string) {
        setSidebarExtended(true)
        const sidebarApi = this.sidebar as unknown as { setPanelSection?: (nextSection: SidebarPanelSectionId) => void }
        if (typeof sidebarApi.setPanelSection == "function") {
            sidebarApi.setPanelSection(section)
        }
        if (selector) {
            window.setTimeout(() => {
                const target = document.querySelector(selector)
                if (target instanceof HTMLElement) {
                    target.scrollIntoView({ block: "nearest", behavior: "smooth" })
                }
            }, 90)
        }
        this.setDesktopLabsOpen(false)
    }

