        this.routeInspectorCloseButton.type = "button"
        this.routeInspectorCloseButton.classList.add("stream-route-inspector-close")
        this.routeInspectorCloseButton.innerText = this.translate("Hide", "Tutup")
        this.routeInspectorCloseButton.title = this.translate("Hide route details", "Sembunyikan detail jalur")
        this.routeInspectorCloseButton.addEventListener("click", (event) => {
            event.preventDefault()
            event.stopPropagation()
            this.setRouteInspectorOpen(false)
        })
        this.routeInspectorTitle.classList.add("stream-route-inspector-title")
        this.routeInspectorMeta.classList.add("stream-route-inspector-meta")
