        const routePresentation = this.getRouteChromePresentation(this.currentRouteState, this.currentRouteDetail)
        this.desktopDebugRoot.dataset.routeState = this.currentRouteState
        this.desktopDebugMeta.innerText = `${routePresentation.label} - ${this.getDesktopDebugRecoveryMeta()}`
        this.desktopDebugGestureValue.innerText = this.getDesktopDebugGestureSummary()
        this.desktopDebugMicValue.innerText = this.getMicrophoneDiagnosticsSummary(true)
