        this.desktopLayoutTemplateClearButton.dataset.active = selectedTemplateMeta.exists && !selectedTemplateMeta.locked ? "true" : "false"

        this.desktopLayoutCompactButton.title = `Switch ${this.getQuickPadOrientationLabelFor(orientation)} layout to Compact`
