        this.desktopBindingsABNintendoButton.title = "Set AB prompts to Nintendo order"
        this.desktopBindingsXYXboxButton.title = "Set XY prompts to Xbox order"
        this.desktopBindingsXYNintendoButton.title = "Set XY prompts to Nintendo order"
