    getSettings(): Settings {
        const settings = this.settings ?? getLocalStreamSettings() ?? defaultSettings()
        return JSON.parse(JSON.stringify(settings))
    }
    updateSettings(nextSettings: Partial<Settings>) {
        const previousBitrate = this.settings.bitrate
        const previousFps = this.settings.fps
        Object.assign(this.settings, nextSettings)
        setLocalStreamSettings(this.settings)
        if (typeof nextSettings.bitrate == "number") {
            this.syncAdaptiveBitrateSessionState(this.settings, nextSettings.bitrate !== previousBitrate)
        }
        if (typeof nextSettings.fps == "number") {
            this.syncAdaptiveFpsSessionState(this.settings, nextSettings.fps !== previousFps)
        }
    }

    private cloneSettingsSnapshot(settings: Settings): Settings {
        return JSON.parse(JSON.stringify(settings)) as Settings
    }

    private getStreamQualityBridgeShortLabel(settings: Settings = this.getSettings()): string {
        const clarityLabel = STREAM_CLARITY_PRESETS[getStreamQualityClarityPresetIdForBitrate(settings.bitrate)].label
        const fpsLabel = String(Math.max(1, Math.round(settings.fps || 60)))
        return `${clarityLabel}/${fpsLabel}`
    }

