    private applyRouteInspectorOpenState() {
        const open = this.routeInspectorOpen
        this.routeInspectorRoot.hidden = !open
        this.routeInspectorRoot.classList.toggle("stream-route-inspector-open", open)
        if (open) {
            document.addEventListener("pointerdown", this.onRouteInspectorOutsidePointerDownBound, { passive: true, capture: true })
            document.addEventListener("touchstart", this.onRouteInspectorOutsidePointerDownBound, { passive: true, capture: true })
        } else {
            document.removeEventListener("pointerdown", this.onRouteInspectorOutsidePointerDownBound, true)
            document.removeEventListener("touchstart", this.onRouteInspectorOutsidePointerDownBound, true)
        }
    }

    private setRouteInspectorOpen(open: boolean) {
        const stats = this.getStream()?.getStats()
        if (open) {
            if (this.statsPanelOpen) {
                this.statsPanelOpen = false
                this.statsDiv.hidden = true
                this.statsCloseButton.hidden = true
            }
            if (this.desktopLabsOpen) {
                this.desktopLabsOpen = false
                this.applyDesktopLabsOpenState()
            }
            if (this.desktopPadOpen) {
                this.desktopPadOpen = false
                this.applyDesktopPadOpenState()
            }
            if (this.desktopLayoutOpen) {
                this.desktopLayoutOpen = false
                this.applyDesktopLayoutOpenState()
            }
            if (this.desktopBindingsOpen) {
                this.desktopBindingsOpen = false
                this.applyDesktopBindingsOpenState()
            }
            if (this.desktopTouchOpen) {
                this.desktopTouchOpen = false
                this.applyDesktopTouchOpenState()
            }
        }
        this.routeInspectorOpen = open
        if (stats) {
            stats.setEnabled(open || this.statsPanelOpen)
        }
        this.applyRouteInspectorOpenState()
        this.syncDesktopUtilityDockState()
    }

    private onRouteInspectorOutsidePointerDown(event: Event) {
        if (!this.routeInspectorOpen) {
            return
        }

        const target = event.target
        if (!(target instanceof Node)) {
            return
        }

        if (this.routeInspectorRoot.contains(target) || this.isRouteInspectorTriggerTarget(target)) {
            return
        }

        this.setRouteInspectorOpen(false)
    }

    private applyAndroidBridgePosition() {
        const viewportWidth = Math.max(window.innerWidth || 0, document.documentElement.clientWidth || 0, 1)
        const topRatio = this.clampAndroidBridgeTopRatio(this.androidBridgePosition.topRatio)
        const edgeOffsetRatio = this.clampAndroidBridgeEdgeOffsetRatio(this.androidBridgePosition.edgeOffsetRatio)
        this.androidBridgePosition.topRatio = topRatio
        this.androidBridgePosition.edgeOffsetRatio = edgeOffsetRatio
        this.androidBridgeRoot.style.setProperty("--android-bridge-top", `${(topRatio * 100).toFixed(1)}%`)
        this.androidBridgeRoot.style.setProperty("--android-bridge-edge-offset", `${Math.round(edgeOffsetRatio * viewportWidth)}px`)
        this.androidBridgeRoot.classList.toggle("android-bridge-left", this.androidBridgePosition.side == "left")
        this.scheduleAndroidBridgeViewportClamp()
    }

