        this.desktopBridgeCompactButton.setAttribute("aria-pressed", this.desktopBridgeCompact ? "true" : "false")
        this.desktopBridgeFullButton.setAttribute("aria-pressed", this.desktopBridgeCompact ? "false" : "true")
        this.desktopBridgeMoreButton.title = this.desktopBridgeCompact
