    private getAndroidBridgeMouseModeIdForConfig(config: StreamInputConfig): AndroidBridgeMouseModeId {
        if (config.touchMode == "pointAndDrag" || config.mouseMode == "pointAndDrag") {
            return "dragdrop"
        }

        return config.mouseMode == "relative" ? "relative" : "follow"
    }

