    private isDesktopLabsWebglStreamEnabled(settings: Settings = this.getSettings()): boolean {
        return !!settings.canvasRenderer && !settings.forceVideoElementRenderer
    }

    private async toggleDesktopLabsWebglStream() {
        const enabled = this.isDesktopLabsWebglStreamEnabled()
        this.updateSettings(enabled
            ? {
                canvasRenderer: false
            }
            : {
                canvasRenderer: true,
                forceVideoElementRenderer: false,
                canvasVsync: false
            }
        )
        this.syncDesktopLabsState()
        await this.reconnectStream(enabled
            ? "experimental webgl stream renderer disabled"
            : "experimental webgl stream renderer enabled"
        )
    }

    private toggleDesktopPadEnabled() {
        const input = this.getStream()?.getInput()
        if (!input) {
            return
        }

        input.setVirtualControllerEnabled(!input.isVirtualControllerEnabled())
        this.sidebar.syncVirtualPadState()
        this.setDesktopPadOpen(true)
    }

    private reconnectDesktopPad() {
        const input = this.getStream()?.getInput()
        if (!input) {
            return
        }

        if (!input.isVirtualControllerEnabled()) {
            input.setVirtualControllerEnabled(true)
        }
        input.reconnectVirtualController()
        this.sidebar.syncVirtualPadState()
        this.setDesktopPadOpen(true)
    }

    private setDesktopPadConflictGuard(enabled: boolean) {
        const orientation = this.getQuickPadCurrentOrientation()
        this.updateQuickPadPrefs({ conflictGuardEnabled: enabled }, orientation)
        this.setDesktopPadOpen(true)
    }

    private applyDesktopPadScenePreset(presetId: GamepadScenePresetId) {
        const orientation = this.getQuickPadCurrentOrientation()
        const preset = GAMEPAD_SCENE_PRESETS[presetId]
        const currentPrefs = this.getQuickPadPrefs(orientation)
        const nextPrefs = {
            ...QUICK_PAD_PRESETS[preset.quickPadPreset],
            ...QUICK_PAD_INPUT_PROFILES[preset.inputProfile],
            inputProfile: preset.inputProfile,
            promptTemplate: currentPrefs.promptTemplate,
            handLayout: currentPrefs.handLayout,
            customButtons: cloneQuickPadCustomButtons(currentPrefs.customButtons)
        }
        this.updateQuickPadPrefs(nextPrefs, orientation)
        this.applyTouchPresetConfig(preset.touchPreset)
        this.setDesktopPadOpen(true)
    }

    private openDesktopPadTrackDeck() {
        this.setDesktopQuickPadEnabled(true)
        this.setDesktopTouchOpen(true)
    }

