    private applyDesktopBindingsConfig(nextConfig: Partial<StreamInputConfig["controllerConfig"]>) {
        const config = this.getInputConfig()
        config.controllerConfig = {
            ...config.controllerConfig,
            ...nextConfig
        }
        this.setInputConfig(config)
        this.setDesktopBindingsOpen(true)
    }

    private setDesktopLayoutProfile(profile: QuickPadOverlayProfile) {
        const orientation = this.getQuickPadCurrentOrientation()
        this.updateQuickPadPrefs({ profile }, orientation)
        this.setDesktopLayoutOpen(true)
    }

    private nudgeDesktopLayoutScale(delta: number) {
        const orientation = this.getQuickPadCurrentOrientation()
        const prefs = this.getQuickPadPrefs(orientation)
        const scale = Math.round(Math.max(0.8, Math.min(1.25, prefs.scale + delta)) * 100) / 100
        this.updateQuickPadPrefs({ scale }, orientation)
        this.setDesktopLayoutOpen(true)
    }

    private cycleDesktopLayoutOpacity() {
        const orientation = this.getQuickPadCurrentOrientation()
        const prefs = this.getQuickPadPrefs(orientation)
        const opacityPresets = [0.7, 0.85, 1]
        const nextOpacity = opacityPresets.find((value) => value > (prefs.opacity + 0.02)) ?? opacityPresets[0]
        this.updateQuickPadPrefs({ opacity: nextOpacity }, orientation)
        this.setDesktopLayoutOpen(true)
    }

    private describeDesktopLayoutTemplateSlot(slotId: QuickPadUserTemplateId) {
        const orientation = this.getQuickPadCurrentOrientation()
        const templateMeta = this.getQuickPadUserTemplateMeta(slotId, orientation)
        const slotLabel = this.getDesktopLayoutTemplateSlotLabel(slotId)
        if (!templateMeta.exists) {
            return `${slotLabel} is empty`
        }
        const buttonCount = orientation === "portrait" ? templateMeta.portraitButtonCount : templateMeta.landscapeButtonCount
        const flags = [`${this.getDesktopLayoutTemplateTypeLabel(templateMeta.layoutType)}`, `${buttonCount} btn${buttonCount === 1 ? "" : "s"}`]
        if (templateMeta.favorite) {
            flags.push("favorite")
        }
        if (templateMeta.locked) {
            flags.push("locked")
        }
        return `${slotLabel}: ${templateMeta.name} (${flags.join(", ")})`
    }

    private setDesktopLayoutTemplateSlot(slotId: QuickPadUserTemplateId) {
        this.desktopLayoutSelectedTemplateSlot = slotId
        this.setDesktopLayoutOpen(true)
    }

    private saveDesktopLayoutTemplate() {
        const templateMeta = this.getDesktopLayoutSelectedTemplateMeta()
        if (templateMeta.locked) {
            return false
        }
        const saved = this.saveQuickPadUserTemplate(this.desktopLayoutSelectedTemplateSlot, templateMeta.name)
        this.setDesktopLayoutOpen(true)
        return saved
    }

    private loadDesktopLayoutTemplate() {
        const templateMeta = this.getDesktopLayoutSelectedTemplateMeta()
        if (!templateMeta.exists) {
            return false
        }
        const loaded = this.loadQuickPadUserTemplate(this.desktopLayoutSelectedTemplateSlot)
        this.setDesktopLayoutOpen(true)
        return loaded
    }

    private toggleDesktopLayoutTemplateFavorite() {
        const templateMeta = this.getDesktopLayoutSelectedTemplateMeta()
        if (!templateMeta.exists) {
            return false
        }
        const updated = this.setQuickPadUserTemplateFavorite(this.desktopLayoutSelectedTemplateSlot, !templateMeta.favorite)
        this.setDesktopLayoutOpen(true)
        return updated
    }

    private clearDesktopLayoutTemplate() {
        const templateMeta = this.getDesktopLayoutSelectedTemplateMeta()
        if (!templateMeta.exists || templateMeta.locked) {
            return false
        }
        const cleared = this.clearQuickPadUserTemplate(this.desktopLayoutSelectedTemplateSlot)
        this.setDesktopLayoutOpen(true)
        return cleared
    }

