        this.androidBridgeActions.addEventListener("scroll", this.onAndroidBridgeActionScrollBound, { passive: true })
        document.addEventListener("pointerdown", this.onAndroidBridgeOutsidePointerDownBound, { capture: true })
        document.addEventListener("touchstart", this.onAndroidBridgeOutsidePointerDownBound, { capture: true, passive: false })
        this.syncAndroidBridgeState()
        this.scheduleAndroidBridgeIdle()
