        // Send keycode
        this.sendKeycodeButton.innerText = "Send Keycode"
        this.sendKeycodeButton.addEventListener("click", async () => {
            const key = await showModal(new SendKeycodeModal())

            if (key == null) {
                return
            }

            this.app.getStream()?.getInput().sendKey(true, key, 0)
            this.app.getStream()?.getInput().sendKey(false, key, 0)
        })
        this.mainButtonDiv.appendChild(this.sendKeycodeButton)

        // Paste text
        this.pasteTextButton.innerText = "Paste Text"
        this.pasteTextButton.addEventListener("click", this.onPasteTextClick.bind(this))
        this.mainButtonDiv.appendChild(this.pasteTextButton)

        // Pointer Lock
        this.lockMouseButton.innerText = "Lock Mouse"
        this.lockMouseButton.addEventListener("click", async () => {
            await this.app.requestPointerLock(true)
        })
        this.mainButtonDiv.appendChild(this.lockMouseButton)

        // Pop up keyboard
        this.keyboardButton.innerText = "Keyboard"
        this.keyboardButton.addEventListener("click", async () => {
            setSidebarExtended(false)
            if (this.app.isAndroidTouchBridgeActive()) {
                this.app.toggleAndroidSoftKeyboard(false)
            } else if (this.screenKeyboard.isVisible()) {
                this.screenKeyboard.hide(true, { explicitClose: true })
            } else {
                this.screenKeyboard.show({ persistent: this.app.isMobileUiMode(), explicitTrigger: true })
            }
        })
        this.mainButtonDiv.appendChild(this.keyboardButton)

        this.screenKeyboard.addKeyDownListener(this.onKeyDown.bind(this))
        this.screenKeyboard.addKeyUpListener(this.onKeyUp.bind(this))
        this.screenKeyboard.addTextListener(this.onText.bind(this))
        this.screenKeyboard.addVisibilityChangeListener(() => {
            this.app.syncAndroidBridgeState()
            this.app.syncDesktopUtilityDockState()
        })


        // Fullscreen
        this.fullscreenButton.innerText = "Clean Fullscreen"
        this.fullscreenButton.addEventListener("click", async () => {
            await this.app.toggleCleanFullscreen()
        })
        this.mainButtonDiv.appendChild(this.fullscreenButton)

        // Stats
        this.statsButton.innerText = "Stats"
        this.statsButton.addEventListener("click", () => {
            const stats = this.app.getStream()?.getStats()
            if (stats) {
                this.app.toggleStatsPanel()
            }
        })
        this.mainButtonDiv.appendChild(this.statsButton)

        // Reconnect stream
        this.reconnectButton.innerText = "Reconnect"
        this.reconnectButton.addEventListener("click", async () => {
            this.reconnectButton.disabled = true
            this.reconnectButton.innerText = "Reconnecting..."
            await this.app.reconnectStream()
        })
        this.mainButtonDiv.appendChild(this.reconnectButton)

        // Close stream
        this.exitStreamButton.innerText = "Exit"
        this.exitStreamButton.addEventListener("click", async () => {
            const stream = this.app.getStream()
            if (stream) {
                const success = await stream.stop()
                if (!success) {
                    console.debug("Failed to close stream correctly")
                }
            }

            if (window.matchMedia('(display-mode: standalone)').matches) {
                history.back()
            } else {
                window.close()
            }

        })
        this.mainButtonDiv.appendChild(this.exitStreamButton)

        // Panel pad
        this.panelPadToggleButton.innerText = this.app.translate("Pad On", "Pad On")
        this.panelPadToggleButton.classList.add("sidebar-stream-button-wide")
