    private startQuickPadUserTemplateRenameHold(slotId: QuickPadUserTemplateId) {
        this.clearQuickPadUserTemplateRenameHold()
        this.quickPadUserTemplateRenameHoldTimer = window.setTimeout(() => {
            this.quickPadUserTemplateRenameHoldTimer = null
            this.armQuickPadUserTemplateSuppressClick(slotId)
            this.quickPadSelectedUserTemplateSlot = slotId
            this.refreshQuickPadTuningControls()
            if (!this.quickPadUserTemplateNameInput.disabled) {
                this.quickPadUserTemplateNameInput.focus()
                this.quickPadUserTemplateNameInput.select()
            }
        }, 420)
    }

    private clearQuickPadUserTemplateRenameHold() {
        if (this.quickPadUserTemplateRenameHoldTimer != null) {
            window.clearTimeout(this.quickPadUserTemplateRenameHoldTimer)
            this.quickPadUserTemplateRenameHoldTimer = null
        }
    }

    private armQuickPadUserTemplateSuppressClick(slotId: QuickPadUserTemplateId) {
        this.clearQuickPadUserTemplateSuppressClick()
        this.quickPadUserTemplateSuppressClickSlot = slotId
        this.quickPadUserTemplateSuppressClickTimer = window.setTimeout(() => {
            this.clearQuickPadUserTemplateSuppressClick()
        }, 900)
    }

    private clearQuickPadUserTemplateSuppressClick() {
        if (this.quickPadUserTemplateSuppressClickTimer != null) {
            window.clearTimeout(this.quickPadUserTemplateSuppressClickTimer)
            this.quickPadUserTemplateSuppressClickTimer = null
        }
        this.quickPadUserTemplateSuppressClickSlot = null
    }

    private onQuickPadUserTemplateSlotClick(slotId: QuickPadUserTemplateId) {
        if (this.quickPadUserTemplateSuppressClickSlot === slotId) {
            this.clearQuickPadUserTemplateSuppressClick()
            return
        }
        const templateMeta = this.app.getQuickPadUserTemplateMeta(slotId, this.quickPadEditorOrientation)
        const warningOrientation = templateMeta.orientationWarning === "portrait_missing"
            ? "portrait"
            : templateMeta.orientationWarning === "landscape_missing"
                ? "landscape"
                : null
        const shouldQuickLoad = templateMeta.exists
            && (slotId === this.quickPadSelectedUserTemplateSlot || templateMeta.favorite)
        this.quickPadSelectedUserTemplateSlot = slotId
        if (warningOrientation != null && this.quickPadEditorOrientation !== warningOrientation) {
            this.app.setQuickPadCustomEditSelection(null)
            this.app.setQuickPadCustomEditMode("off")
            this.quickPadCustomBuilderSlotIndex = null
            this.setQuickPadEditorOrientation(warningOrientation)
            this.focusQuickPadCustomStartAction()
            return
        }
        if (shouldQuickLoad) {
            this.app.loadQuickPadUserTemplate(slotId)
        }
        this.refreshQuickPadTuningControls()
    }

    private focusQuickPadCustomStartAction() {
        window.requestAnimationFrame(() => {
            const primaryTarget = !this.quickPadCustomAddButton.disabled
                ? this.quickPadCustomAddButton
                : !this.quickPadCustomPresetWasdButton.hidden && !this.quickPadCustomPresetWasdButton.disabled
                    ? this.quickPadCustomPresetWasdButton
                    : !this.quickPadCustomGenreShooterButton.hidden && !this.quickPadCustomGenreShooterButton.disabled
                        ? this.quickPadCustomGenreShooterButton
                        : null
            this.clearQuickPadCustomStartActionGuide()
            primaryTarget?.classList.add("quick-pad-guided-action")
            primaryTarget?.scrollIntoView({ behavior: "smooth", block: "nearest" })
            primaryTarget?.focus()
            if (primaryTarget != null) {
                this.quickPadCustomStartActionGuideTimer = window.setTimeout(() => {
                    this.clearQuickPadCustomStartActionGuide()
                }, 1800)
            }
        })
    }

    private clearQuickPadCustomStartActionGuide() {
        if (this.quickPadCustomStartActionGuideTimer != null) {
            window.clearTimeout(this.quickPadCustomStartActionGuideTimer)
            this.quickPadCustomStartActionGuideTimer = null
        }
        ;[
            this.quickPadCustomAddButton,
            this.quickPadCustomPresetWasdButton,
            this.quickPadCustomPresetActionButton,
            this.quickPadCustomPresetSystemButton,
            this.quickPadCustomPresetShortcutButton,
            this.quickPadCustomGenreShooterButton,
            this.quickPadCustomGenreRacingButton,
            this.quickPadCustomGenreMobaButton,
            this.quickPadCustomGenreMmoButton
        ].forEach((button) => button.classList.remove("quick-pad-guided-action"))
    }

    private async onQuickPadUserTemplateSaveClick() {
        const templateMeta = this.getSelectedQuickPadUserTemplateMeta()
        if (templateMeta.locked) {
            await showMessage(this.app.translate(
                `Unlock reusable template "${templateMeta.name}" first if you want to replace it.`,
                `Buka dulu kunci template reusable "${templateMeta.name}" kalau mau menimpanya.`
            ))
            return
        }
        const templateName = sanitizeQuickPadUserTemplateName(this.quickPadUserTemplateNameInput.value)
            || this.getQuickPadUserTemplateDefaultName(this.quickPadSelectedUserTemplateSlot)
        this.quickPadUserTemplateNameInput.value = templateName
        const saved = this.app.saveQuickPadUserTemplate(this.quickPadSelectedUserTemplateSlot, templateName)
        if (!saved) {
            await showMessage(this.app.translate(
                "Could not save that reusable template right now.",
                "Template reusable itu belum bisa disimpan sekarang."
            ))
            return
        }
        this.refreshQuickPadTuningControls()
        await showMessage(this.app.translate(
            `Saved reusable QuickPad template "${templateName}" on this browser.`,
            `Template QuickPad reusable "${templateName}" sudah disimpan di browser ini.`
        ))
    }

