    private async onQuickPadUserTemplatePasteClick() {
        const templateMeta = this.getSelectedQuickPadUserTemplateMeta()
        if (templateMeta.locked) {
            await showMessage(this.app.translate(
                `Unlock reusable template "${templateMeta.name}" first if you want to paste into it.`,
                `Buka dulu kunci template reusable "${templateMeta.name}" kalau mau menempel ke slot itu.`
            ))
            return
        }
        let text = ""

        if (navigator.clipboard && typeof navigator.clipboard.readText == "function") {
            try {
                text = await navigator.clipboard.readText()
            } catch {
                // fall back to prompt below
            }
        }

        if (!text) {
            text = window.prompt(
                this.app.translate("Paste reusable template JSON:", "Tempel JSON template reusable:"),
                ""
            ) ?? ""
        }

        if (!text) {
            return
        }

        const importedMeta = this.app.importQuickPadUserTemplate(this.quickPadSelectedUserTemplateSlot, text)
        if (!importedMeta) {
            await showMessage(this.app.translate(
                "Reusable template JSON is not valid.",
                "JSON template reusable tidak valid."
            ))
            return
        }

        this.app.loadQuickPadUserTemplate(this.quickPadSelectedUserTemplateSlot)
        this.refreshQuickPadTuningControls()
        await showMessage(this.app.translate(
            `Reusable template "${importedMeta.name}" imported and applied.`,
            `Template reusable "${importedMeta.name}" berhasil diimpor dan langsung dipakai.`
        ))
    }

    private async onQuickPadUserTemplatePasteAllClick() {
        let text = ""

        if (navigator.clipboard && typeof navigator.clipboard.readText == "function") {
            try {
                text = await navigator.clipboard.readText()
            } catch {
                // fall back to prompt below
            }
        }

        if (!text) {
            text = window.prompt(
                this.app.translate("Paste all reusable template JSON:", "Tempel JSON semua template reusable:"),
                ""
            ) ?? ""
        }

        if (!text) {
            return
        }

        const importResult = this.app.importQuickPadUserTemplateStore(text)
        if (!importResult.ok) {
            await showMessage(this.app.translate(
                importResult.reason === "locked"
                    ? "Unlock every locked reusable template slot first before Paste All."
                    : "Reusable template bundle JSON is not valid.",
                importResult.reason === "locked"
                    ? "Buka dulu semua slot template reusable yang terkunci sebelum Tempel Semua."
                    : "JSON bundle template reusable tidak valid."
            ))
            return
        }

        this.refreshQuickPadTuningControls()
        await showMessage(this.app.translate(
            `Imported ${importResult.importedCount} reusable QuickPad template slot(s).`,
            `${importResult.importedCount} slot template QuickPad reusable berhasil diimpor.`
        ))
    }

